module RefModule(
    input DATA, LATCH,
    output Q, QNOT
    );wire obf_d, l;
    reg q, qnot;

    assign obf_d = DATA;
    assign l = LATCH;

    always@(obf_d or l)
        if(l)begin
            q <= obf_d;
            qnot <= ~obf_d;
        end

    assign Q = q;
    assign QNOT = qnot;endmodule
